  7→/// Overflow behavior: drops oldest samples (same as Swift version).
  8→#[derive(Debug)]
  9→pub struct RingBuffer {
 10→    buffer: Vec<f32>,
 11→    write_index: usize,
 12→    read_index: usize,
 13→    available: usize,
 14→    capacity: usize,
 15→}
 16→
 17→impl RingBuffer {
 18→    pub fn new(capacity: usize) -> Self {
 19→        Self {
 20→            buffer: vec![0.0; capacity],
 21→            write_index: 0,
 22→            read_index: 0,
 23→            available: 0,
 24→            capacity,
 25→        }
 26→    }
 27→
 28→    /// Write samples into the ring buffer.
 29→    ///
 30→    /// If the buffer overflows, the oldest samples are dropped.
 31→    /// If `samples` is larger than capacity, only the last `capacity` samples are kept.
 32→    pub fn write(&mut self, samples: &[f32]) {
 33→        if samples.is_empty() {
 34→            return;
 35→        }
 36→
 37→        // If more data than capacity, only keep the tail
 38→        let samples = if samples.len() > self.capacity {
 39→            &samples[samples.len() - self.capacity..]
 40→        } else {
 41→            samples
 42→        };
 43→
 44→        // Drop oldest if we'd overflow
 45→        let overflow = (self.available + samples.len()).saturating_sub(self.capacity);
 46→        if overflow > 0 {
 47→            self.read_index = (self.read_index + overflow) % self.capacity;
 48→            self.available -= overflow;
 49→        }
 50→
 51→        // Write samples into circular buffer
 52→        for &sample in samples {
 53→            self.buffer[self.write_index] = sample;
 54→            self.write_index = (self.write_index + 1) % self.capacity;
 55→        }
 56→        self.available += samples.len();
 57→    }
 58→
 59→    /// Read and remove up to `count` samples from the buffer.
 60→    ///
 61→    /// Returns fewer samples if fewer are available.
 62→    pub fn read(&mut self, count: usize) -> Vec<f32> {
 63→        let to_read = count.min(self.available);
 64→        if to_read == 0 {
 65→            return Vec::new();
 66→        }
 67→
 68→        let mut result = Vec::with_capacity(to_read);
 69→        for i in 0..to_read {
 70→            result.push(self.buffer[(self.read_index + i) % self.capacity]);
 71→        }
 72→        self.read_index = (self.read_index + to_read) % self.capacity;
 73→        self.available -= to_read;
 74→        result
 75→    }
 76→
 77→    /// Number of samples currently available for reading.
 78→    pub fn count(&self) -> usize {
 79→        self.available
 80→    }
 81→
 82→    /// Whether the buffer is empty.
 83→    pub fn is_empty(&self) -> bool {
 84→        self.available == 0
 85→    }
 86→
 87→    /// Reset the buffer to empty state.
 88→    pub fn reset(&mut self) {
 89→        self.write_index = 0;
 90→        self.read_index = 0;
 91→        self.available = 0;
 92→    }
 93→
 94→    /// The total capacity of the buffer.
 95→    pub fn capacity(&self) -> usize {
 96→        self.capacity
 97→    }
 98→}
