  5→// MARK: - Audio Processing, Timers & Buffer Callbacks
  6→
  7→extension CompositeCaptureSession {
  8→    func startDurationTimer() {
  9→        durationTimer = Task { [weak self] in
 10→            while !Task.isCancelled {
 11→                try? await Task.sleep(nanoseconds: 250_000_000)
 12→                guard let self, !Task.isCancelled else { break }
 13→
 14→                let currentState = sessionState.withLock { $0.state }
 15→                if case .capturing = currentState {
 16→                    let duration = elapsedDuration()
 17→                    setState(.capturing(duration: duration))
 18→
 19→                    if let maxDuration = configuration.maxDuration, duration >= maxDuration {
 20→                        _ = try? await stopCapture()
 21→                        break
 22→                    }
 23→                }
 24→            }
 25→        }
 26→    }
 27→
 28→    func startProcessingLoop() {
 29→        processingTask = Task { [weak self] in
 30→            while !Task.isCancelled {
 31→                try? await Task.sleep(nanoseconds: 100_000_000)
 32→                guard let self, !Task.isCancelled else { break }
 33→
 34→                let currentState = sessionState.withLock { $0.state }
 35→                if case .capturing = currentState {
 36→                    await processBuffers()
 37→                }
 38→            }
 39→        }
 40→    }
 41→
 42→    func processBuffers() async {
 43→        guard let writer = fileWriter else { return }
 44→
 45→        let config = configuration
 46→        let chunkSize = Int(config.sampleRate * 0.1) // 100ms frames
 47→        guard let (micSamples, systemSamples) =
 48→            await readPendingSamples(config: config, chunkSize: chunkSize) else { return }
 49→
 50→        // Deliver raw channel buffers to delegate before mixing
 51→        let channelBuffers = ChannelBuffers(
 52→            micSamples: micSamples,
 53→            systemSamples: systemSamples,
 54→            sampleRate: stereoMixer.targetSampleRate
 55→        )
 56→        let preDelegate = sessionState.withLock { $0.delegate }
 57→        preDelegate?.captureSession(self, didProduceChannelBuffers: channelBuffers)
 58→
 59→        let stereoSamples = stereoMixer.mix(
 60→            mic: micSamples,
 61→            system: systemSamples,
 62→            strategy: configuration.mixingStrategy
 63→        )
 64→        let pcmData = stereoMixer.convertToInt16PCM(stereoSamples)
 65→
 66→        if config.exportRawPCM {
 67→            writeRawPCMSidecars(micSamples: micSamples, systemSamples: systemSamples)
 68→        }
 69→
 70→        sessionState.withLock {
 71→            $0.diagnostics.mixCycles += 1
 72→            $0.diagnostics.bytesWritten += pcmData.count
 73→        }
 74→
 75→        do {
 76→            try await writer.write(pcmData)
 77→        } catch {
 78→            let delegate = sessionState.withLock { $0.delegate }
 79→            if let captureError = error as? CaptureError {
 80→                delegate?.captureSession(self, didEncounterError: captureError)
 81→            }
 82→        }
 83→    }
 84→
 85→    private func readPendingSamples(
 86→        config: CaptureConfiguration,
 87→        chunkSize: Int
 88→    ) async -> (mic: [Float], system: [Float])? {
 89→        guard let micBuf = micBuffer, let sysBuf = systemBuffer else { return nil }
 90→
 91→        if config.enableSystemCapture {
 92→            let frames = await min(sysBuf.count / 2, chunkSize)
 93→            guard frames > 0 else { return nil }
 94→            return await (mic: micBuf.read(count: frames), system: sysBuf.read(count: frames * 2))
 95→        } else {
 96→            let mic = await micBuf.read(count: chunkSize)
 97→            return mic.isEmpty ? nil : (mic: mic, system: [])
 98→        }
 99→    }
100→
101→    private func writeRawPCMSidecars(micSamples: [Float], systemSamples: [Float]) {
102→        let (micHandle, systemHandle) = sessionState.withLock {
103→            ($0.micPCMFileHandle, $0.systemPCMFileHandle)
104→        }
105→        if let micHandle {
106→            let micPCM = stereoMixer.convertToInt16PCM(micSamples)
107→            micHandle.write(micPCM)
108→        }
109→        if let systemHandle {
110→            let systemPCM = stereoMixer.convertToInt16PCM(systemSamples)
111→            systemHandle.write(systemPCM)
112→        }
113→    }
114→
115→    // MARK: - Audio Buffer Callbacks
116→
117→    /// Processes a single mic audio buffer from AVFoundation.
118→    func handleMicBuffer(_ buffer: AVAudioPCMBuffer) {
119→        let sampleRate = buffer.format.sampleRate
120→        let formatDesc =
121→            "\(Int(sampleRate))Hz \(buffer.format.channelCount)ch "
122→                + "\(buffer.format.isInterleaved ? "int" : "non-int")"
123→
124→        guard let samples = AudioFormatConverter.extractMonoSamples(from: buffer) else {
125→            logger.warning("Mic: extractMonoSamples returned nil for \(formatDesc)")
126→            return
127→        }
128→        let resampled = stereoMixer.resample(samples, from: sampleRate)
129→        updateMicLevel(samples: resampled)
130→        sessionState.withLock {
131→            $0.diagnostics.micCallbackCount += 1
132→            $0.diagnostics.micSamplesTotal += resampled.count
133→            $0.diagnostics.micFormat = formatDesc
134→        }
135→        Task { await micBuffer?.write(resampled) }
136→    }
137→
138→    /// Processes a single system audio buffer from Core Audio tap.
139→    func handleSystemBuffer(_ buffer: AVAudioPCMBuffer) {
140→        let reportedRate = buffer.format.sampleRate
141→        let channelCount = Int(buffer.format.channelCount)
142→        let targetRate = stereoMixer.targetSampleRate
143→        let formatDesc =
144→            "\(Int(reportedRate))Hz \(channelCount)ch "
145→                + "\(buffer.format.isInterleaved ? "int" : "non-int")"
146→
147→        guard let samples = AudioFormatConverter.extractFloatSamples(from: buffer) else {
148→            logger.warning("System: extractFloatSamples returned nil for \(formatDesc)")
149→            return
150→        }
151→
152→        let sysCount = sessionState.withLock { $0.diagnostics.systemCallbackCount }
153→        if sysCount == 0 {
154→            logFirstSystemCallback(buffer: buffer, samples: samples, targetRate: targetRate)
155→        }
156→
157→        let resampled = resampleSystemAudio(samples, channelCount: channelCount, sourceRate: targetRate)
158→
159→        if sysCount == 0 {
160→            logger.info("System audio after resample: in=\(samples.count) out=\(resampled.count)")
161→        }
162→
163→        updateSystemLevel(samples: resampled)
164→        sessionState.withLock {
165→            $0.diagnostics.systemCallbackCount += 1
166→            $0.diagnostics.systemSamplesTotal += resampled.count
167→            $0.diagnostics.systemFormat = "\(Int(reportedRate))->\(Int(targetRate))Hz \(channelCount)ch"
168→        }
169→        Task { await systemBuffer?.write(resampled) }
170→    }
171→
172→    private func logFirstSystemCallback(buffer: AVAudioPCMBuffer, samples: [Float], targetRate: Double) {
173→        let rate = buffer.format.sampleRate
174→        let ch = Int(buffer.format.channelCount)
175→        logger.info("System audio: \(rate)Hz, target=\(targetRate)Hz, \(buffer.frameLength)fr, \(ch)ch")
176→        logger.info("System audio detail: \(samples.count) samples")
177→    }
178→
179→    private func resampleSystemAudio(_ samples: [Float], channelCount: Int, sourceRate: Double) -> [Float] {
180→        if channelCount >= 2 {
181→            return stereoMixer.resampleStereo(samples, from: sourceRate)
182→        }
183→        let mono = stereoMixer.resample(samples, from: sourceRate)
184→        return stereoMixer.interleave(left: mono, right: mono)
185→    }
