187→    // MARK: - Level Metering
188→
189→    func updateMicLevel(samples: [Float]) {
190→        guard !samples.isEmpty else { return }
191→        let rms = sqrt(samples.map { $0 * $0 }.reduce(0, +) / Float(samples.count))
192→        let peak = samples.map { abs($0) }.max() ?? 0
193→
194→        let current = sessionState.withLock { $0.currentLevels }
195→
196→        setLevels(AudioLevels(
197→            micLevel: rms,
198→            systemLevel: current.systemLevel,
199→            peakMicLevel: max(peak, current.peakMicLevel),
200→            peakSystemLevel: current.peakSystemLevel
201→        ))
202→    }
203→
204→    func updateSystemLevel(samples: [Float]) {
205→        guard !samples.isEmpty else { return }
206→        let rms = sqrt(samples.map { $0 * $0 }.reduce(0, +) / Float(samples.count))
207→        let peak = samples.map { abs($0) }.max() ?? 0
208→
209→        let current = sessionState.withLock { $0.currentLevels }
210→
211→        setLevels(AudioLevels(
212→            micLevel: current.micLevel,
213→            systemLevel: rms,
214→            peakMicLevel: current.peakMicLevel,
215→            peakSystemLevel: max(peak, current.peakSystemLevel)
216→        ))
217→    }
