219→    // MARK: - Mic Rate Detection
220→
221→    /// Starts mic capture briefly to detect the actual sample rate after
222→    /// Bluetooth HFP negotiation. Waits up to 500ms for the rate to stabilize.
223→    func detectMicRate(config: CaptureConfiguration) async throws -> Double {
224→        let lowestRate = UnfairLock(config.sampleRate)
225→
226→        try await micCapture.start { buffer, _ in
227→            let rate = buffer.format.sampleRate
228→            lowestRate.withLock { current in
229→                if rate < current { current = rate }
230→            }
231→        }
232→
233→        try? await Task.sleep(nanoseconds: 500_000_000)
234→
235→        let result = lowestRate.withLock { $0 }
236→        logger.info("Mic rate probe detected: \(result)Hz (after 500ms settling)")
237→        return result
238→    }
