240→    // MARK: - Recording Finalization
241→
242→    /// Closes the file writer and builds the recording result.
243→    func finalizeRecording() async throws -> RecordingResult {
244→        guard let writer = fileWriter else {
245→            throw CaptureError.storageError("No file writer available")
246→        }
247→
248→        let detectedRate = sessionState.withLock { $0.detectedMicRate }
249→        let actualRate = detectedRate.map { min($0, configuration.sampleRate) }
250→
251→        let checksum: String
252→        do {
253→            checksum = try await writer.close(
254→                actualSampleRate: actualRate,
255→                channels: UInt16(configuration.channels),
256→                bitDepth: UInt16(configuration.bitDepth)
257→            )
258→        } catch {
259→            setState(.failed(.storageError("Failed to close file")))
260→            throw error
261→        }
262→
263→        let rawPCMURLs: [URL] = sessionState.withLock {
264→            $0.micPCMFileHandle?.closeFile()
265→            $0.micPCMFileHandle = nil
266→            $0.systemPCMFileHandle?.closeFile()
267→            $0.systemPCMFileHandle = nil
268→            return $0.rawPCMFileURLs
269→        }
270→
271→        let result = buildRecordingResult(checksum: checksum, rawPCMFileURLs: rawPCMURLs)
272→        setState(.completed(result))
273→
274→        let delegate = sessionState.withLock { $0.delegate }
275→        delegate?.captureSession(self, didFinishCapture: result)
276→        return result
277→    }
278→
279→    private func buildRecordingResult(checksum: String, rawPCMFileURLs: [URL] = []) -> RecordingResult {
280→        let duration = elapsedDuration()
281→        let config = configuration
282→        let fileURL: URL = sessionState.withLock { $0.fileURL! }
283→
284→        let (tracks, channelLayout): ([AudioTrack], ChannelLayout)
285→        switch config.mixingStrategy {
286→        case .separated, .multichannel:
287→            tracks = [
288→                AudioTrack(type: .mic, channel: .left, label: "Mic (Local)"),
289→                AudioTrack(type: .system, channel: .right, label: "System (Remote, mono-fold)"),
290→            ]
291→            channelLayout = .separatedStereo
292→        case .blended:
293→            tracks = [
294→                AudioTrack(type: .mic, channel: .center),
295→                AudioTrack(type: .system, channel: .stereo),
296→            ]
297→            channelLayout = .blended
298→        }
299→
300→        let metadata = RecordingMetadata(
301→            duration: duration,
302→            fileURL: fileURL,
303→            checksum: checksum,
304→            isEncrypted: config.encryptor != nil,
305→            tracks: tracks,
306→            encryptionAlgorithm: config.encryptor?.algorithm,
307→            encryptionKeyId: config.encryptor?.keyMetadata()["keyId"],
308→            channelLayout: channelLayout
309→        )
310→
311→        return RecordingResult(
312→            fileURL: fileURL,
313→            duration: duration,
314→            metadata: metadata,
315→            checksum: checksum,
316→            rawPCMFileURLs: rawPCMFileURLs
317→        )
318→    }
319→}
