  1→import AVFoundation
  2→import CoreAudio
  3→import Crypto
  4→import Foundation
  5→import os
  6→
  7→/// A composite capture session that combines microphone and system audio.
  8→///
  9→/// `CompositeCaptureSession` is the primary implementation of ``AudioCaptureSession``.
 10→/// It coordinates a ``CoreAudioTapCapture`` (system audio, right channel) and an
 11→/// ``AVFoundationMicCapture`` (microphone, left channel), mixing them into stereo
 12→/// PCM and writing the result to an optionally encrypted WAV file.
 13→///
 14→/// ## State Machine
 15→/// ```
 16→/// idle -> configuring -> ready -> capturing <-> paused
 17→///                                    |              |
 18→///                                    v              v
 19→///                                 stopping -> completed
 20→///                                    |
 21→///                                    v
 22→///                                  failed
 23→/// ```
 24→public final class CompositeCaptureSession: @unchecked Sendable {
 25→    struct SessionState {
 26→        var state: CaptureState = .idle
 27→        var delegate: (any AudioCaptureDelegate)?
 28→        var configuration: CaptureConfiguration
 29→        var currentLevels: AudioLevels = .zero
 30→        var captureStartTime: Date?
 31→        var pausedDuration: TimeInterval = 0
 32→        var lastPauseTime: Date?
 33→        var fileURL: URL?
 34→        var diagnostics = CaptureSessionDiagnostics()
 35→        /// Actual mic sample rate detected from the first callback (may differ from config).
 36→        var detectedMicRate: Double?
 37→        var micPCMFileHandle: FileHandle?
 38→        var systemPCMFileHandle: FileHandle?
 39→        var rawPCMFileURLs: [URL] = []
 40→    }
 41→
 42→    let sessionState: UnfairLock<SessionState>
 43→
 44→    let micCapture: AVFoundationMicCapture
 45→    let systemCapture: CoreAudioTapCapture
 46→    var stereoMixer: StereoMixer
 47→
 48→    var fileWriter: EncryptedFileWriter?
 49→    var micBuffer: AudioBufferManager?
 50→    var systemBuffer: AudioBufferManager?
 51→
 52→    var durationTimer: Task<Void, Never>?
 53→    var processingTask: Task<Void, Never>?
 54→
 55→    let logger = Logger(
 56→        subsystem: "com.audiocapturekit",
 57→        category: "CompositeCaptureSession"
 58→    )
 59→
 60→    /// Creates a new composite capture session.
 61→    /// - Parameter configuration: Initial configuration. Can be updated via ``configure(_:)``.
 62→    public init(configuration: CaptureConfiguration) {
 63→        self.sessionState = UnfairLock(SessionState(configuration: configuration))
 64→        self.micCapture = AVFoundationMicCapture(deviceID: configuration.micDeviceID)
 65→        self.systemCapture = CoreAudioTapCapture()
 66→        self.stereoMixer = StereoMixer(targetSampleRate: configuration.sampleRate)
 67→    }
 68→
 69→    func setState(_ newState: CaptureState) {
 70→        let delegate: (any AudioCaptureDelegate)? = sessionState.withLock {
 71→            $0.state = newState
 72→            return $0.delegate
 73→        }
 74→
 75→        delegate?.captureSession(self, didChangeState: newState)
 76→    }
 77→
 78→    func setLevels(_ levels: AudioLevels) {
 79→        let delegate: (any AudioCaptureDelegate)? = sessionState.withLock {
 80→            $0.currentLevels = levels
 81→            return $0.delegate
 82→        }
 83→
 84→        delegate?.captureSession(self, didUpdateLevels: levels)
 85→    }
 86→
 87→    func elapsedDuration() -> TimeInterval {
 88→        sessionState.withLock { state in
 89→            guard let startTime = state.captureStartTime else { return 0 }
 90→            let totalElapsed = Date().timeIntervalSince(startTime)
 91→            let currentPauseDuration: TimeInterval = if let pauseTime = state.lastPauseTime {
 92→                Date().timeIntervalSince(pauseTime)
 93→            } else {
 94→                0
 95→            }
 96→            return totalElapsed - state.pausedDuration - currentPauseDuration
 97→        }
 98→    }
 99→}
100→
101→// MARK: - AudioCaptureSession
102→
103→extension CompositeCaptureSession: AudioCaptureSession {
104→    public var state: CaptureState {
105→        sessionState.withLock { $0.state }
106→    }
107→
108→    public var delegate: (any AudioCaptureDelegate)? {
109→        get { sessionState.withLock { $0.delegate } }
110→        set { sessionState.withLock { $0.delegate = newValue } }
