133→
134→        setState(.configuring)
135→
136→        guard configuration.sampleRate > 0 else {
137→            setState(.failed(.configurationFailed("Invalid sample rate")))
138→            throw CaptureError.configurationFailed("Sample rate must be positive")
139→        }
140→        guard [16, 24, 32].contains(configuration.bitDepth) else {
141→            setState(.failed(.configurationFailed("Invalid bit depth")))
142→            throw CaptureError.configurationFailed("Bit depth must be 16, 24, or 32")
143→        }
144→        // Channels 1–2 are active; 3–4 are reserved for future multi-mic support.
145→        // The mixer currently produces 2-channel output regardless of channel count.
146→        guard (1 ... 4).contains(configuration.channels) else {
147→            setState(.failed(.configurationFailed("Invalid channel count")))
148→            throw CaptureError.configurationFailed("Channel count must be 1–4")
149→        }
