190→    public func resumeCapture() throws {
191→        let currentState = sessionState.withLock { $0.state }
192→        guard case .paused = currentState else {
193→            throw CaptureError.configurationFailed("Cannot resume when not paused")
194→        }
195→
196→        sessionState.withLock { state in
197→            if let pauseTime = state.lastPauseTime {
198→                state.pausedDuration += Date().timeIntervalSince(pauseTime)
199→            }
200→            state.lastPauseTime = nil
201→        }
202→        let elapsed = elapsedDuration()
203→        setState(.capturing(duration: elapsed))
