206→    public func stopCapture() async throws -> RecordingResult {
207→        let currentState = sessionState.withLock { $0.state }
208→        switch currentState {
209→        case .capturing, .paused:
210→            break
211→        default:
212→            throw CaptureError.configurationFailed(
213→                "Cannot stop when not capturing or paused"
214→            )
215→        }
216→
217→        setState(.stopping)
218→
219→        await micCapture.stop()
220→        await systemCapture.stop()
