234→    /// Detects the actual mic sample rate (HFP probe) and configures the mixer.
235→    private func resolveOutputRate(config: CaptureConfiguration) async throws -> Double {
236→        var actualMicRate = config.sampleRate
237→
238→        if config.enableMicCapture {
239→            actualMicRate = try await detectMicRate(config: config)
240→            logger.info("Mic actual rate after HFP negotiation: \(actualMicRate)Hz")
241→        }
242→
243→        let outputRate = min(actualMicRate, config.sampleRate)
244→        logger.info("Output rate: \(outputRate)Hz")
245→
246→        stereoMixer = StereoMixer(targetSampleRate: outputRate)
247→        sessionState.withLock { $0.detectedMicRate = actualMicRate }
248→
249→        return outputRate
250→    }
