252→    /// Creates ring buffers and opens the file writer with the confirmed rate.
253→    private func prepareFileWriter(
254→        config: CaptureConfiguration,
255→        outputRate: Double
256→    ) async throws {
257→        let bufferCapacity = Int(outputRate * config.bufferDurationSeconds)
258→        micBuffer = AudioBufferManager(capacity: bufferCapacity)
259→        systemBuffer = AudioBufferManager(capacity: bufferCapacity * 2)
260→
261→        let fileName = "recording_\(UUID().uuidString)"
262→        let ext = config.encryptor != nil ? "enc.wav" : "wav"
263→        let fileURL = config.outputDirectory.appendingPathComponent("\(fileName).\(ext)")
264→        let writer = EncryptedFileWriter(fileURL: fileURL, encryptor: config.encryptor)
265→        fileWriter = writer
266→        sessionState.withLock { $0.fileURL = fileURL }
267→
268→        let outputConfig = CaptureConfiguration(
269→            sampleRate: outputRate,
270→            bitDepth: config.bitDepth,
271→            channels: config.channels,
272→            encryptor: config.encryptor,
273→            outputDirectory: config.outputDirectory,
274→            maxDuration: config.maxDuration,
275→            micDeviceID: config.micDeviceID,
276→            enableMicCapture: config.enableMicCapture,
277→            enableSystemCapture: config.enableSystemCapture,
278→            mixingStrategy: config.mixingStrategy,
279→            exportRawPCM: config.exportRawPCM
280→        )
281→
282→        do {
283→            try await writer.open(configuration: outputConfig)
284→        } catch {
285→            setState(.failed(.storageError("Failed to open file")))
286→            throw error
287→        }
288→
289→        if config.exportRawPCM {
290→            openPCMSidecarFiles(baseName: fileName, directory: config.outputDirectory)
291→        }
292→    }
