294→    /// Opens PCM sidecar files for raw channel export.
295→    private func openPCMSidecarFiles(baseName: String, directory: URL) {
296→        let micURL = directory.appendingPathComponent("\(baseName)_mic.pcm")
297→        let systemURL = directory.appendingPathComponent("\(baseName)_system.pcm")
298→        let fm = FileManager.default
299→
300→        var handles: (mic: FileHandle?, system: FileHandle?) = (nil, nil)
301→
302→        if fm.createFile(atPath: micURL.path, contents: nil) {
303→            handles.mic = FileHandle(forWritingAtPath: micURL.path)
304→        } else {
305→            logger.warning("Failed to create mic PCM sidecar at \(micURL.path)")
306→        }
307→
308→        if fm.createFile(atPath: systemURL.path, contents: nil) {
309→            handles.system = FileHandle(forWritingAtPath: systemURL.path)
310→        } else {
311→            logger.warning("Failed to create system PCM sidecar at \(systemURL.path)")
312→        }
313→
314→        sessionState.withLock {
315→            $0.micPCMFileHandle = handles.mic
316→            $0.systemPCMFileHandle = handles.system
317→            var urls: [URL] = []
318→            if handles.mic != nil { urls.append(micURL) }
319→            if handles.system != nil { urls.append(systemURL) }
320→            $0.rawPCMFileURLs = urls
321→        }
322→    }
